    <style type="text/css">
        body {
            background: #FAFCFF;
            font-family: 'Inter', sans-serif;
        }
        .card{
            border: unset;
            width: 100%;
            border-radius: 3px;
        }
        .card-body{
            border-radius: 3px;
            padding: 10px;
        }
        .p-0 {
            padding: 0px;
        }

        .m-0 {
            margin: 0px;
        }

        /* width */
        ::-webkit-scrollbar {
            width: 5px;
        }

        /* Track */
        ::-webkit-scrollbar-track {
            border-radius: 3px;
            background: #F0F0F0;
        }

        /* Handle */
        ::-webkit-scrollbar-thumb {
            background: rgba(65, 162, 226, 0.8);
            border-radius: 3px;
        }

        .collaps-cust [type="radio"]:checked,
        .collaps-cust [type="radio"]:not(:checked) {
            display: none;
        }
        .collaps-cust [type="radio"]:checked + label,
        .collaps-cust [type="radio"]:not(:checked) + label
        {
            position: absolute;
            top: 15px;
            left: 40px;
            bottom: 0px;
            width: 100%;
            cursor: pointer;
        }
        .collaps-cust [type="radio"]:checked + label:before,
        .collaps-cust [type="radio"]:not(:checked) + label:before {
            content: '';
            position: absolute;
            left: 0;
            top: 0;
            width: 18px;
            height: 18px;
            border: 1px solid #8FB5E1;
            border-radius: 100%;
            background: #fff;
        }
        .collaps-cust [type="radio"]:checked + label:after,
        .collaps-cust [type="radio"]:not(:checked) + label:after {
            content: '';
            width: 12px;
            height: 12px;
            background: #8FB5E1;
            position: absolute;
            top: 3px;
            left: 3px;
            border-radius: 100%;
            -webkit-transition: all 0.2s ease;
            transition: all 0.2s ease;
        }
        .collaps-cust [type="radio"]:not(:checked) + label:after {
            opacity: 0;
            -webkit-transform: scale(0);
            transform: scale(0);
        }
        .collaps-cust [type="radio"]:checked + label:after {
            opacity: 1;
            -webkit-transform: scale(1);
            transform: scale(1);
        }
        .paymentOption{
            min-height:calc(100vh - 120px);
        }

        .accordion .collaps-cust{
            overflow: hidden;
        }
        .accordion .card{
            border: 1px solid #E6ECF9;
            margin-bottom: 10px;
        }
        .accordion .card-header{
            background-color: #FFFFFF;
            border-radius: 3px;
            border: unset;
            cursor: pointer;
            padding: 15px 30px 15px 40px;
            position: relative;
            overflow : hidden;
        }
        .accordion .card-header.collapsed{
            background-color: #EFF3FB;
        }
        .accordion .card-header .icon{
            float: right;
            width: 75px;
            height: 72px;
            text-align: center;
            margin-right: 10px;
        }
        .accordion .card-header .title{
            float: left;
            margin-left: 35px;
            max-width: 62%;
        }

        label{
            color: #1E293B;
            font-size: 18px;
            width: 100%;
        }
        .accordion .card-header h5{
            font-size: 18px;
            color: #374263;
        }
        small,
        .accordion .card-header span{
            color: #B4BCC7;
            font-size: 14px;
        }
        .accordion .card-body{
            padding: 0px 45px 45px 45px;
        }
        .accordion .card:last-child{
            margin-bottom: 0px;
        }

        .btn-pay-now{
            box-shadow: 0px 10px 10px 0px #6D92F04D;
            background: #0153C8;
            color: #FFF;
            border-radius: 3px;
        }

        .card-container {
          width: 100%;
          position: relative;
        }
        .card-container input {
          width: 100%;
          padding-left: 60px;
        }
        .card-type {
            width: 50px;
            height: 23px;
            position: absolute;
            top: 7px;
            left: 16px;
            border-right: 1px solid #C0CCDA;
            text-align: center;
            line-height: 0;
            font-size: 24px;
            color: #133E5E;
        }
        
        .card-valid {
          position: absolute;
          top: 6px;
          right: 25px;
          line-height: 0;
        }

        .lds-hourglass {
            display: inline-block;
            position: relative;
            width: 80px;
            height: 80px;
        }
        .lds-hourglass:after {
            content: " ";
            display: block;
            border-radius: 50%;
            width: 0;
            height: 0;
            margin: 8px;
            box-sizing: border-box;
            border: 32px solid #000;
            border-color: #000 transparent #000 transparent;
            animation: lds-hourglass 1.2s infinite;
        }
        .company-name-titles-changes{
            padding : 15px 0px;
        }
        @keyframes  lds-hourglass {
            0% {
                transform: rotate(0);
                animation-timing-function: cubic-bezier(0.55, 0.055, 0.675, 0.19);
            }
            50% {
                transform: rotate(900deg);
                animation-timing-function: cubic-bezier(0.215, 0.61, 0.355, 1);
            }
            100% {
                transform: rotate(1800deg);
            }
        }

        .preventscreenclick{
            width: 100%;
            height: 100%;
            position: fixed;
            top: 0px;
            left: 0px;
            display: none;
        }

    </style>
</head>

