        var connId = $("input[name='connector_id']").val();
        var valid_vpa = $("input[name='valid_vpa']").val();
        var processing_type = $("input[name='processing_type']:checked").val();
        $.ajax({
            url: '{{$modifiedUrlStatus}}',
            type: 'post',
            data: {
                id: connId,
                valid_vpa: valid_vpa,
                amount: "{{$amount}}",
                currency: "INR"
            },
            success: function (resp) {
                if (resp.status) {
                    swal({
                        title: 'Are you sure, You want to continue?',
                        text: resp.message,
                        icon: "warning",
                        button: "Yes, I am sure!",
                        dangerMode: true,
                    }).then(function (retVal) {
                        if (retVal) {
                            $("#connector-form").submit();
                        }
                    });
                } else {
                    if (valid_vpa == 0) {
                        $('#customer-error-vpa-valid').show();
                        $('#customer-error-vpa').hide();
                        $('#customer-success-vpa').hide();
                    }else{
                        $("#connector-form").submit();
                    }
                }
            }
        });
    }

</script>



</body></html>